#!/bin/bash
# {{PROJECT_NAME}} — Session entry script
# Generated by the wizard. Do not edit manually.
#
# Usage (run from project directory):
#   ./start-session.sh                    Standard start
#   ./start-session.sh --resume           Resume after planned pause
#   ./start-session.sh --resume --alert   Resume to respond to an alert

set -euo pipefail

# ── Status-line convention (F-36 fix) ───────────────────────────────────────
# Every operator-runnable emitted script carries this SAME block (kept
# byte-identical on purpose -- see test_status_line_convention.py). It
# guarantees ONE unambiguous terminal line plus a real exit code no matter
# where or why the script exits: an explicit `exit N` below, or an exit
# `set -e` forces on a line this script's own logic never anticipated. A
# `!`-run command must never finish silently (empty output, exit 0) and be
# mistaken for having done nothing (dogfood finding F-36).
_STATUS_LINE_REPORTED=false
_report_status_line() {
  local _exit_code=$?
  trap - EXIT
  if [ "$_STATUS_LINE_REPORTED" != true ]; then
    _STATUS_LINE_REPORTED=true
    if [ "$_exit_code" -eq 0 ]; then
      echo "RESULT: done"
    else
      echo "RESULT: failed (exit ${_exit_code})" >&2
    fi
  fi
  exit "$_exit_code"
}
trap _report_status_line EXIT
# ── end status-line convention ──────────────────────────────────────────────

# Model — resolved by the wizard from the tier mapping at setup time.
# The high tier carries a trailing [1m] suffix to select the 1-million-token context
# window in Claude Code. That variant is not available on every account/plan, so we name
# a graceful fallback: the same model id with [1m] stripped (the standard 200K window).
# --fallback-model engages it if the 1M variant is unavailable. For a non-1M model id the
# fallback equals the model (no degradation). ${MODEL%\[1m\]} removes a trailing literal "[1m]".
MODEL="{{MODEL_HIGH}}"
FALLBACK_MODEL="${MODEL%\[1m\]}"

# Resolve project directory from the script's own location
PROJECT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$PROJECT_DIR"

# ── Parse flags ───────────────────────────────────────────────────────────────

RESUME=false
ALERT=false

for arg in "$@"; do
    case "$arg" in
        --resume) RESUME=true ;;
        --alert)  ALERT=true ;;
        *)
            echo ""
            echo "Unknown flag: $arg"
            echo "Usage: ./start-session.sh [--resume] [--alert]"
            echo ""
            exit 1
            ;;
    esac
done

# --alert without --resume is not a valid combination
if $ALERT && ! $RESUME; then
    echo ""
    echo "--alert must be used together with --resume."
    echo "Usage: ./start-session.sh --resume --alert"
    echo ""
    exit 1
fi

# ── Prerequisite checks ───────────────────────────────────────────────────────

# Claude Code CLI
if ! command -v claude &>/dev/null; then
    echo ""
    echo "Claude Code is not installed or cannot be found."
    echo "Run this to install it: npm install -g @anthropic-ai/claude-code"
    echo "Or see manual.md in this directory for the full setup guide."
    echo ""
    exit 1
fi

# Correct directory
if [ ! -f "session_bootstrap.md" ]; then
    echo ""
    echo "Cannot find session_bootstrap.md."
    echo "Make sure you are running this script from the project directory."
    echo "Expected location: $PROJECT_DIR"
    echo ""
    exit 1
fi

if [ ! -f "CLAUDE.md" ]; then
    echo ""
    echo "Cannot find CLAUDE.md."
    echo "Make sure you are running this script from the project directory."
    echo "Expected location: $PROJECT_DIR"
    echo ""
    exit 1
fi

# ── Python venv bootstrap (F-35 fix) ─────────────────────────────────────────
# Dogfood finding F-35: an emitted Python-shape system ran on whatever ancient
# `python3` macOS happened to have (never checked, never installed, no venv, no
# declared deps) -- the operator had to fix this by hand. The fix: this project's
# requirements.txt is emitted ONLY for a writes-back/Python-dependent system (see
# agent_emitter._emit_requirements_txt) -- its presence is the single signal this whole
# block keys off. A system with no Python component has no requirements.txt, and this
# entire block is a silent no-op: no venv, no interpreter check, no dead scaffolding.
PYTHON_FLOOR_MAJOR=3
PYTHON_FLOOR_MINOR=11

_python_meets_floor() {
  # $1: path to a python interpreter. 0 (true) iff its version >= the floor above.
  "$1" -c "import sys; sys.exit(0 if sys.version_info[:2] >= (${PYTHON_FLOOR_MAJOR}, ${PYTHON_FLOOR_MINOR}) else 1)" 2>/dev/null
}

_resolve_modern_python() {
  # Never assumes the operator's PATH resolves a current `python3` (same discipline as
  # programmatic --model selection): tries dedicated version binaries first, then a
  # Homebrew prefix lookup (works even when Homebrew's own bin dir isn't linked onto
  # PATH), and only falls back to bare `python3` after actually verifying its version.
  local candidate
  for candidate in python3.13 python3.12 python3.11; do
    if command -v "$candidate" &>/dev/null && _python_meets_floor "$(command -v "$candidate")"; then
      command -v "$candidate"
      return 0
    fi
  done
  if command -v brew &>/dev/null; then
    local brew_prefix
    brew_prefix="$(brew --prefix python@3.12 2>/dev/null || true)"
    if [ -n "$brew_prefix" ] && [ -x "$brew_prefix/bin/python3.12" ] \
       && _python_meets_floor "$brew_prefix/bin/python3.12"; then
      echo "$brew_prefix/bin/python3.12"
      return 0
    fi
  fi
  if command -v python3 &>/dev/null && _python_meets_floor "$(command -v python3)"; then
    command -v python3
    return 0
  fi
  return 1
}

if [ -f "requirements.txt" ]; then
    MODERN_PYTHON="$(_resolve_modern_python || true)"
    if [ -z "$MODERN_PYTHON" ]; then
        echo ""
        echo "This system needs Python ${PYTHON_FLOOR_MAJOR}.${PYTHON_FLOOR_MINOR} or newer to run its Python components, and none was found."
        echo "Run this to install it: brew install python@3.12"
        echo "Then run ./start-session.sh again."
        echo ""
        exit 1
    fi

    # Create (or recreate, if a stale sub-floor .venv exists from before this fix) the
    # project-local venv on the resolved modern interpreter. Never the operator's bare
    # python3 -- always this exact, verified copy.
    if [ ! -x ".venv/bin/python" ] || ! _python_meets_floor ".venv/bin/python"; then
        rm -rf .venv
        "$MODERN_PYTHON" -m venv .venv
    fi

    # Idempotent: pip is a fast no-op when requirements are already satisfied.
    .venv/bin/python -m pip install --quiet --disable-pip-version-check -r requirements.txt

    # Pin the interpreter for the REST of this session: prepend the venv's bin/ (which
    # contains its own `python`/`python3`/`python3.x`) to PATH so any python command run
    # in this session -- by you, or by an agent's own bash tool call -- resolves to this
    # pinned interpreter, never a stray system python3.
    export PATH="$PROJECT_DIR/.venv/bin:$PATH"

    # ── Python end-of-life upkeep reminder ──────────────────────────────────
    # Plain-language heads-up if the pinned interpreter is nearing or past its public
    # end-of-life, in the same "tell the operator, give the exact fix command" voice as
    # the rest of this script and the CLAUDE.md upgrade-notice mechanism. Dates are
    # CPython's own published end-of-life schedule (PEP 602 cadence).
    _VENV_PY_VERSION="$(.venv/bin/python -c 'import sys; print("%d.%d" % sys.version_info[:2])' 2>/dev/null || true)"
    _PY_EOL_DATE=""
    case "$_VENV_PY_VERSION" in
        3.9)  _PY_EOL_DATE="2025-10-05" ;;
        3.10) _PY_EOL_DATE="2026-10-04" ;;
        3.11) _PY_EOL_DATE="2027-10-24" ;;
        3.12) _PY_EOL_DATE="2028-10-02" ;;
        3.13) _PY_EOL_DATE="2029-10-01" ;;
        3.14) _PY_EOL_DATE="2030-10-01" ;;
        *)    _PY_EOL_DATE="" ;;
    esac
    if [ -n "$_PY_EOL_DATE" ]; then
        _TODAY_EPOCH=$(date -u +%s)
        _EOL_EPOCH=$(date -u -j -f "%Y-%m-%d" "$_PY_EOL_DATE" +%s 2>/dev/null || date -u -d "$_PY_EOL_DATE" +%s 2>/dev/null || echo "")
        if [ -n "$_EOL_EPOCH" ]; then
            _DAYS_LEFT=$(( (_EOL_EPOCH - _TODAY_EPOCH) / 86400 ))
            if [ "$_DAYS_LEFT" -lt 0 ]; then
                echo ""
                echo "Heads up: this project's Python (${_VENV_PY_VERSION}) reached end-of-life on ${_PY_EOL_DATE} and no longer receives security fixes."
                echo "Run this when you have a moment: brew install python@3.12"
                echo ""
            elif [ "$_DAYS_LEFT" -lt 180 ]; then
                echo ""
                echo "Heads up: this project's Python (${_VENV_PY_VERSION}) reaches end-of-life on ${_PY_EOL_DATE}."
                echo "No action needed yet -- when you have a moment: brew install python@3.12"
                echo ""
            fi
        fi
    fi
fi
# ── end Python venv bootstrap ─────────────────────────────────────────────────

# ── Banner ────────────────────────────────────────────────────────────────────

# Kickoff prompt — the FIRST message handed to the session so it orients itself and
# greets you, instead of opening to a silent, blank prompt. (Claude Code does not take a
# turn until it receives a message; without this, running this script just launches Claude
# and waits, with no sign of what to do next.) The session orients SILENTLY from the
# startup files, then presents a plain-language lay of the land and the single next step —
# no internal file names, no internal state labels, no menu of options, no flagging that
# internal files disagree (that goes to the logs, not to you).
KICKOFF="Begin this session. First, SILENTLY follow the session startup sequence in CLAUDE.md (read session_bootstrap.md and the other startup files it lists) to orient yourself -- do NOT narrate which files you read. Then greet me in plain, non-technical language: in one or two sentences say what this system is for, tell me whether anything needs my attention right now, and give me the SINGLE recommended next step. Do NOT show internal details (file names, internal state labels like 'built' or 'Layer-A', or notes that internal files disagree with each other) -- if you notice an internal inconsistency, record it in the logs and reconcile it yourself, do not raise it to me. Do NOT give me a menu of choices; lead with the one next step. End by asking me a simple yes/no to go ahead, and wait for my answer before doing anything."

echo ""
if $ALERT; then
    echo "{{PROJECT_NAME}} — Alert response"
    echo "Loading system state. This will take a moment."
    echo "─────────────────────────────────────────────────────────"
    KICKOFF="This is an alert-response session. Read /logs/notification_log.md FIRST, identify what triggered the alert, and tell me in plain, non-technical language what it is and the single recommended response before doing anything else. Do NOT show internal file names or state labels, and do not give me a menu. Then wait for my go-ahead before acting."
elif $RESUME; then
    echo "{{PROJECT_NAME}} — Resuming session"
    echo "─────────────────────────────────────────────────────────"
else
    echo "{{PROJECT_NAME}} — Starting session"
    echo "─────────────────────────────────────────────────────────"
fi
echo ""

# ── Launch Claude Code ────────────────────────────────────────────────────────

# --effort high: this system's sessions reason at the high tier (the wizard resolved
# MODEL_HIGH above). Extended-thinking budgets are not a CLI flag; --effort is the
# supported knob for session reasoning effort (low|medium|high|xhigh|max).
# --fallback-model: degrade to the standard-context model if the 1M-context [1m] variant
# is unavailable on this account/plan, so launch never hard-fails over the context window.
# The trailing positional argument is the kickoff prompt (the session's first message),
# so the session orients + surfaces the next step instead of waiting at a blank prompt.
claude --model "$MODEL" --fallback-model "$FALLBACK_MODEL" --effort high "$KICKOFF"
